import Foundation

// Interactive calculator
print("Simple Calculator")
print("Enter first number:")
guard let firstInput = readLine(), let firstNum = Double(firstInput) else {
    print("Invalid input")
    exit(1)
}

print("Enter second number:")
guard let secondInput = readLine(), let secondNum = Double(secondInput) else {
    print("Invalid input")
    exit(1)
}

print("Operator (+, -, *, /):")
guard let op = readLine() else {
    print("Invalid operator")
    exit(1)
}

var result: Double
switch op {
case "+": result = firstNum + secondNum
case "-": result = firstNum - secondNum
case "*": result = firstNum * secondNum
case "/": result = secondNum != 0 ? firstNum / secondNum : 0
default: print("Unknown operator"); exit(1)
}

print("Result: \(result)")
